#!/usr/bin/env node
import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const requestedModuleName = process.argv[2];

if (!requestedModuleName) {
  console.error(
    'Usage: node open-source/gnosis/scripts/promote-gnosis-math-module-theorems.mjs <GnosisModule|--all|--declarations-all|--module-surfaces-all|--normalize-ids>'
  );
  process.exit(1);
}

const repoRoot = process.cwd();
const gnosisMathRoot = path.join(repoRoot, 'open-source/gnosis-math/Gnosis');
const ledgerPath = path.join(repoRoot, 'open-source/gnosis/THEOREM_LEDGER.md');

function stripLeanComments(source) {
  let output = '';
  for (let index = 0; index < source.length; ) {
    if (source.startsWith('/-', index)) {
      let depth = 1;
      index += 2;
      while (index < source.length && depth > 0) {
        if (source.startsWith('/-', index)) {
          depth += 1;
          index += 2;
        } else if (source.startsWith('-/', index)) {
          depth -= 1;
          index += 2;
        } else {
          index += 1;
        }
      }
    } else if (source.startsWith('--', index)) {
      while (index < source.length && source[index] !== '\n') index += 1;
    } else if (source[index] === '"') {
      index += 1;
      while (index < source.length) {
        if (source[index] === '\\') {
          index += 2;
        } else if (source[index] === '"') {
          index += 1;
          break;
        } else {
          index += 1;
        }
      }
    } else {
      output += source[index];
      index += 1;
    }
  }
  return output;
}

function stripLeanCommentsKeepStrings(source) {
  let output = '';
  for (let index = 0; index < source.length; ) {
    if (source.startsWith('/-', index)) {
      let depth = 1;
      index += 2;
      while (index < source.length && depth > 0) {
        if (source.startsWith('/-', index)) {
          depth += 1;
          index += 2;
        } else if (source.startsWith('-/', index)) {
          depth -= 1;
          index += 2;
        } else {
          index += 1;
        }
      }
    } else if (source.startsWith('--', index)) {
      while (index < source.length && source[index] !== '\n') index += 1;
    } else {
      output += source[index];
      index += 1;
    }
  }
  return output;
}

function theoremDeclarations(source) {
  const declarations = [];
  const namespaces = [];
  for (const line of stripLeanComments(source).split('\n')) {
    const namespaceMatch = line.match(/^namespace\s+(\S+)/u);
    if (namespaceMatch) {
      namespaces.push(namespaceMatch[1]);
      continue;
    }
    if (/^end\s*(\S+)?/u.test(line)) {
      namespaces.pop();
      continue;
    }
    const theoremMatch = line.match(/^theorem\s+([A-Za-z0-9_]+)/u);
    if (theoremMatch) {
      declarations.push({
        theoremName: theoremMatch[1],
        namespace: namespaces.join('.'),
      });
    }
  }
  return declarations;
}

function formalDeclarations(source) {
  const declarations = [];
  const namespaces = [];
  for (const line of stripLeanCommentsKeepStrings(source).split('\n')) {
    const namespaceMatch = line.match(/^namespace\s+(\S+)/u);
    if (namespaceMatch) {
      namespaces.push(namespaceMatch[1]);
      continue;
    }
    if (/^end\s*(\S+)?/u.test(line)) {
      namespaces.pop();
      continue;
    }
    const declarationMatch = line.match(
      /^(def|structure|inductive|class|abbrev|macro)\s+([A-Za-z0-9_'."]+)/u
    );
    if (declarationMatch) {
      const declarationName = declarationMatch[2].replace(/^"|"$/gu, '');
      declarations.push({
        kind: declarationMatch[1],
        declarationName,
        namespace: namespaces.join('.'),
      });
    }
  }
  return declarations;
}

function titleFromTheorem(theoremName) {
  return theoremName.replaceAll('_', ' ').replace(/\b[a-z]/gu, (letter) =>
    letter.toUpperCase()
  );
}

function idSuffix(value) {
  return value
    .replace(/([a-z0-9])([A-Z])/gu, '$1-$2')
    .replace(/[^A-Za-z0-9]+/gu, '-')
    .replace(/^-|-$/gu, '')
    .toUpperCase();
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/gu, '\\$&');
}

function renderRows(moduleName, declarations) {
  const moduleId = idSuffix(moduleName);
  return declarations
    .map(({ theoremName, namespace }) => {
      const fullName = namespace ? `${namespace}.${theoremName}` : theoremName;
      const theoremId = `THM-GNOSIS-MATH-${moduleId}-${idSuffix(theoremName)}`;
      return `| \`${theoremId}\` | ${moduleName} formalizes ${titleFromTheorem(theoremName)}. | Lean declaration \`${theoremName}\` in namespace \`${namespace || '(root)'}\` | Lean theorem \`${fullName}\` in \`Gnosis/${moduleName}.lean\` | \`mechanized\` |`;
    })
    .join('\n');
}

function renderDeclarationRows(moduleName, declarations) {
  const moduleId = idSuffix(moduleName);
  return declarations
    .map(({ kind, declarationName, namespace }) => {
      const fullName = namespace ? `${namespace}.${declarationName}` : declarationName;
      const declarationId = `THM-GNOSIS-MATH-DECL-${moduleId}-${idSuffix(declarationName)}`;
      return `| \`${declarationId}\` | ${moduleName} exposes formal ${kind} declaration \`${declarationName}\`. | Lean ${kind} declaration \`${declarationName}\` in namespace \`${namespace || '(root)'}\`; theorem-free module, so this is a declaration-level MCP anchor | Lean declaration \`${fullName}\` in \`Gnosis/${moduleName}.lean\` | \`declared\` |`;
    })
    .join('\n');
}

function renderModuleSurfaceRow(moduleName) {
  const moduleId = idSuffix(moduleName);
  const moduleSurfaceId = `THM-GNOSIS-MATH-MODULE-${moduleId}`;
  return `| \`${moduleSurfaceId}\` | ${moduleName} exposes a formal Lean module surface. | Import-only or placeholder Lean module with no theorem, lemma, definition, type, or macro declarations; kept as an explicit module-level MCP anchor | Lean module \`${moduleName}\` in \`Gnosis/${moduleName}.lean\` | \`declared\` |`;
}

function normalizeGeneratedIds(ledger) {
  const startMarker = '<!-- gnosis-math-mcp-placement:start -->';
  const endMarker = '<!-- gnosis-math-mcp-placement:end -->';
  const start = ledger.indexOf(startMarker);
  const end = ledger.indexOf(endMarker);
  if (start === -1 || end === -1 || end < start) return { ledger, changed: 0 };

  const before = ledger.slice(0, start);
  const block = ledger.slice(start, end);
  const after = ledger.slice(end);
  let changed = 0;
  const normalizedBlock = block.replace(
    /^\| `(THM-(?!GNOSIS-MATH-)[^`]+)` \|/gmu,
    (_match, theoremId) => {
      changed += 1;
      return `| \`THM-GNOSIS-MATH-${theoremId.slice('THM-'.length)}\` |`;
    }
  );
  return { ledger: `${before}${normalizedBlock}${after}`, changed };
}

function readLeanModule(moduleName) {
  const leanPath = path.join(gnosisMathRoot, `${moduleName}.lean`);
  if (!existsSync(leanPath)) {
    throw new Error(`Lean module not found: ${path.relative(repoRoot, leanPath)}`);
  }
  return readFileSync(leanPath, 'utf8');
}

function placementRowPattern(moduleName) {
  const placementId = `THM-GNOSIS-MATH-PLACEMENT-${idSuffix(moduleName)}`;
  return new RegExp(`^\\| \`${escapeRegExp(placementId)}\` \\| .*$`, 'mu');
}

function promoteOne(ledger, moduleName) {
  const declarations = theoremDeclarations(readLeanModule(moduleName));
  if (declarations.length === 0) {
    return { ledger, promoted: false, theoremCount: 0 };
  }

  const rowPattern = placementRowPattern(moduleName);
  if (!rowPattern.test(ledger)) {
    throw new Error(
      `Placement row not found for ${moduleName}: THM-GNOSIS-MATH-PLACEMENT-${idSuffix(moduleName)}`
    );
  }

  return {
    ledger: ledger.replace(rowPattern, renderRows(moduleName, declarations)),
    promoted: true,
    theoremCount: declarations.length,
  };
}

function promoteDeclarationsOne(ledger, moduleName) {
  const declarations = formalDeclarations(readLeanModule(moduleName));
  if (declarations.length === 0) {
    return { ledger, promoted: false, declarationCount: 0 };
  }

  const rowPattern = placementRowPattern(moduleName);
  if (!rowPattern.test(ledger)) {
    throw new Error(
      `Placement row not found for ${moduleName}: THM-GNOSIS-MATH-PLACEMENT-${idSuffix(moduleName)}`
    );
  }

  return {
    ledger: ledger.replace(rowPattern, renderDeclarationRows(moduleName, declarations)),
    promoted: true,
    declarationCount: declarations.length,
  };
}

function promoteModuleSurfaceOne(ledger, moduleName) {
  const rowPattern = placementRowPattern(moduleName);
  if (!rowPattern.test(ledger)) {
    throw new Error(
      `Placement row not found for ${moduleName}: THM-GNOSIS-MATH-PLACEMENT-${idSuffix(moduleName)}`
    );
  }

  return {
    ledger: ledger.replace(rowPattern, renderModuleSurfaceRow(moduleName)),
    promoted: true,
  };
}

function remainingPlacementModules(ledger) {
  const modules = [];
  const pattern =
    /^\| `THM-GNOSIS-MATH-PLACEMENT-[^`]+` \| MCP placement anchor for Gnosis Math module `([^`]+)`\..*$/gmu;
  for (const match of ledger.matchAll(pattern)) {
    modules.push(match[1]);
  }
  return modules;
}

try {
  let ledger = readFileSync(ledgerPath, 'utf8');
  if (requestedModuleName === '--normalize-ids') {
    const result = normalizeGeneratedIds(ledger);
    writeFileSync(ledgerPath, result.ledger, 'utf8');
    console.log(`Normalized ${result.changed} generated theorem IDs.`);
  } else if (requestedModuleName === '--all') {
    const modules = remainingPlacementModules(ledger);
    let promotedModules = 0;
    let promotedTheorems = 0;
    const theoremlessModules = [];

    for (const moduleName of modules) {
      const result = promoteOne(ledger, moduleName);
      ledger = result.ledger;
      if (result.promoted) {
        promotedModules += 1;
        promotedTheorems += result.theoremCount;
      } else {
        theoremlessModules.push(moduleName);
      }
    }

    writeFileSync(ledgerPath, ledger, 'utf8');
    console.log(
      `Promoted ${promotedTheorems} theorem rows across ${promotedModules} modules.`
    );
    console.log(
      `Left ${theoremlessModules.length} theorem-free placement anchors.`
    );
    if (theoremlessModules.length > 0) {
      console.log(theoremlessModules.join('\n'));
    }
  } else if (requestedModuleName === '--declarations-all') {
    const modules = remainingPlacementModules(ledger);
    let promotedModules = 0;
    let promotedDeclarations = 0;
    const importOnlyModules = [];

    for (const moduleName of modules) {
      const result = promoteDeclarationsOne(ledger, moduleName);
      ledger = result.ledger;
      if (result.promoted) {
        promotedModules += 1;
        promotedDeclarations += result.declarationCount;
      } else {
        importOnlyModules.push(moduleName);
      }
    }

    writeFileSync(ledgerPath, ledger, 'utf8');
    console.log(
      `Promoted ${promotedDeclarations} declaration rows across ${promotedModules} modules.`
    );
    console.log(`Left ${importOnlyModules.length} import-only placement anchors.`);
    if (importOnlyModules.length > 0) {
      console.log(importOnlyModules.join('\n'));
    }
  } else if (requestedModuleName === '--module-surfaces-all') {
    const modules = remainingPlacementModules(ledger);
    let promotedModules = 0;

    for (const moduleName of modules) {
      const result = promoteModuleSurfaceOne(ledger, moduleName);
      ledger = result.ledger;
      if (result.promoted) {
        promotedModules += 1;
      }
    }

    writeFileSync(ledgerPath, ledger, 'utf8');
    console.log(`Promoted ${promotedModules} module surface rows.`);
  } else {
    const result = promoteOne(ledger, requestedModuleName);
    if (!result.promoted) {
      throw new Error(`No theorem declarations found in ${requestedModuleName}.`);
    }
    writeFileSync(ledgerPath, result.ledger, 'utf8');
    console.log(
      `Promoted ${result.theoremCount} theorem rows for ${requestedModuleName}.`
    );
  }
} catch (error) {
  console.error(error instanceof Error ? error.message : error);
  process.exit(1);
}
